mapper.select:
SELECT cur.order_sn AS orderSn, COALESCE(SUM((hist_price.price - cur.price) * cur.quantity_real), 0) AS costReduction FROM erp_purchase_order_item cur LEFT JOIN ( SELECT i2.sku, i2.order_sn AS exclude_order_sn, i2.price, ROW_NUMBER() OVER (PARTITION BY i2.sku, i2.order_sn ORDER BY o2.lx_create_time DESC) AS rn FROM erp_purchase_order_item i2 JOIN erp_purchase_order o2 ON o2.order_sn = i2.order_sn ) hist_price ON hist_price.sku = cur.sku AND hist_price.exclude_order_sn != cur.order_sn AND hist_price.rn = 1 WHERE cur.order_sn IN
#{sn}
GROUP BY cur.order_sn

SELECT i.price, o.lx_create_time AS purchaseDate
FROM erp_purchase_order_item i
JOIN erp_purchase_order o ON o.order_sn = i.order_sn
WHERE i.sku = #{sku}
  AND i.order_sn != #{excludeOrderSn}
ORDER BY o.lx_create_time ASC
LIMIT #{limit}
